def finish_task(summary: str, extra_notes=None):
    # Step 1: Validate and clean the main summary
    if not isinstance(summary, str) or not summary.strip():
        raise ValueError("A non‑empty summary string is required for FINISH.")
    clean_summary = summary.strip()

    # Step 2: Prepare the list of messages to send to FINISH
    messages = [clean_summary]
    if extra_notes:
        if not isinstance(extra_notes, list):
            raise TypeError("extra_notes must be a list of strings if provided.")
        # Trim each extra note and filter out empty strings
        for note in extra_notes:
            if isinstance(note, str) and note.strip():
                messages.append(note.strip())

    # Step 3: Call the FINISH tool with the prepared message list
    FINISH(messages)

